var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"돌기둥 두 개가 나란히 세워진 오솔길…….","JPN":"石柱が2本並んだ小道……","ENG":"A trail with two stone pillars...","TWN":"兩根石柱整齊排列的的小路……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아무래도 여기가 맞는 것 같네.","JPN":"どうやらここであってるみたいだ。","ENG":"I think this is it.","TWN":"應該是這裡沒錯。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"장님 동굴?","JPN":"晦冥の洞窟？","ENG":"The Cave of Blinds?","TWN":"盲穴？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 이름처럼 입구를 닫으면 빛 한 점 들지 않는 동굴입니다.","JPN":"はい。その名のとおり、入口を閉じると\\n光がまったく入らない洞窟のことです。","ENG":"Yes. As its name suggests, you can’t see anything in the cave when the entrance is closed.","TWN":"是的，就像它的名字一樣，入口關閉後，完全是伸手不見五指的洞穴。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"길이 미로처럼 복잡하고 넓어서. 저희 나나하라 가문이 가진 무녀의 신력을 증명하는 장소로 쓰이곤 했어요.","JPN":"道が迷路のように複雑で広いため、我が七原家が持つ巫女の神力を\\n証明する場所としてよく使われていました。","ENG":"Since its path is like a maze, the Nanahara family has been using this place to prove our divine power as priestesses.","TWN":"路又大又寬敞像迷宮一樣，要證明七原家族巫女的神力時，常常都會選在這裡。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주를 선발하는 시험도 전통적으로 그곳에서 치르게 되어 있습니다.","JPN":"当主を選抜する試練もここで行うのが伝統です。","ENG":"We’ve also been using it as the testing ground for choosing the next family leader.","TWN":"傳統上，選拔堂主的競賽也是那裡進行。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 나는 그동안 뭘 하면 될까? 시험에서 이기게 도와 주면 되는 거야?","JPN":"じゃあ、僕は何をすればいい？　試練に勝てるように手伝えばいいの？","ENG":"So what do I do? Help you to win the competition?","TWN":"那這段時間我要做什麼？幫你贏得競賽嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아뇨. 시험은 상관없습니다.","JPN":"いいえ、試練については大丈夫です。","ENG":"Never mind the competition.","TWN":"不，重點不是競賽。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"시험 도중에 동굴 입구는 무너지고, 전 동굴에 갇히게 될 테니까요.","JPN":"試練の途中に洞窟の入口が崩れ、\\n私は洞窟に閉じ込められてしまいますから。","ENG":"The cave entrance will collapse during the competition, and I’ll be locked up in there.","TWN":"競賽過程中洞口會崩塌，我會被困在洞穴裡。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그건…… 단순한 사고가 아닌 거지? 누구 짓인지는 알 수 없어?","JPN":"それは……単なる事故じゃないんだよね？　誰の仕業かはわからないのか？","ENG":"So that’s not a simple accident, is it? Do you know who’s the culprit?","TWN":"那……應該不是單純的意外吧？有辦法知道是誰做的嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저도 노력해 봤습니다만……. 탁한 기운이 그 정체를 감추고 있었어요.","JPN":"私も努力しましたが……濁ったオーラがその正体を隠しています。","ENG":"I tried... but a dark cloud was hiding the one behind all this.","TWN":"我有嘗試過……但濁氣遮住他的真面目。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 지금 저희에게 그 자의 정체는 중요하지 않습니다.","JPN":"しかし、今の私たちにとってその者の正体は重要なことではありません。","ENG":"But the identity of the culprit is not important for now.","TWN":"不過現在對我們而言，那個人的身分不重要。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희가 이미 그 함정을 간파하고 있으니까요.","JPN":"私たちはすでにその罠を看破しているのですから。","ENG":"We already know what they will do.","TWN":"因爲我們已經知道那個陷阱。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"<b>미나토 님은 제가 말씀드리는 장소에 먼저 가 주세요.</b>","JPN":"<b>湊様は私がお伝えする場所へ先に向かってください。</b>","ENG":"<b>Mr. Nayuka, please go to the place I tell you.</b>","TWN":"<b>南裕夏，要請你先到我說的那個地方。</b>"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"돌기둥 두 개를 사이에 두고 스무 걸음을 물러선 다음에…….","JPN":"石柱を2本見つけたら、その間から20歩下がり……","ENG":"Stand between the two stone pillars, walk twenty steps back...","TWN":"隔著兩根石柱後退二十步後……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"<b>화살을 쏘면 됩니다.</b>","JPN":"<b>矢を放つのです。</b>","ENG":"<b>And then you shoot an arrow.</b>","TWN":"<b>然後射箭。</b>"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"두 돌기둥의 중심점이 향하는 장님 동굴의 가장 얇은 벽이면……. 저기란 말이지.","JPN":"2本の石柱の中心点が示す、晦冥の洞窟の最も薄い壁……あそこだな。","ENG":"The thinnest wall in the Cave of Blinds, seen between the two stone pillars... Okay.","TWN":"兩根石柱的中心點朝向盲穴最薄的牆……就是那裡。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};